// pages/graphkit-scaffold.js
// Handler scaffold preview for project-side GraphKit runtime semantics.
(function registerGraphKitScaffoldApi(root) {
    const model = typeof module !== 'undefined' && module.exports
        ? require('./graphkit-model.js')
        : root;

    function generateGraphKitHandlerScaffold(project) {
        const sanitized = model.sanitizeGraphKitProject(project);
        const classNames = new Set();
        const lines = [
            '// Generated by YokiFrame GraphKit from Luban XML nodeTypes.',
            '// Keep runtime semantics in project code; GraphKit only owns data.',
            'using System;',
            '',
            'namespace YokiFrame.GraphKit.Generated',
            '{',
            '    public interface IGraphNodeHandler',
            '    {',
            '        string HandlerId { get; }',
            '        void Execute(GraphNodeDefinition node, GraphRuntimeContext context);',
            '    }',
            '',
        ];

        sanitized.nodeTypes.forEach(type => {
            const handlerId = type.handlerId || type.id;
            const className = makeUniqueGraphKitHandlerClassName(handlerId, type.id, classNames);
            lines.push(`    public sealed class ${className} : IGraphNodeHandler`);
            lines.push('    {');
            lines.push(`        public string HandlerId { get { return "${escapeGraphKitCSharpString(handlerId)}"; } }`);
            lines.push('');
            lines.push('        public void Execute(GraphNodeDefinition node, GraphRuntimeContext context)');
            lines.push('        {');
            const fieldLines = makeGraphKitHandlerFieldLines(type);
            if (fieldLines.length) fieldLines.forEach(line => lines.push(`            ${line}`));
            else lines.push('            _ = node;');
            lines.push('            _ = context;');
            lines.push(`            // TODO: Implement ${escapeGraphKitCSharpComment(type.title || type.id)} semantics.`);
            lines.push('        }');
            lines.push('    }');
            lines.push('');
        });

        lines.push('}');
        return lines.join('\n');
    }

    function makeGraphKitHandlerFieldLines(type) {
        return (type.fields || []).map(field => {
            const variableName = toGraphKitCSharpIdentifier(field.name || 'field', 'field');
            const accessor = getGraphKitFieldAccessor(field.type);
            return `${getGraphKitCSharpType(field.type)} ${variableName} = node.${accessor}("${escapeGraphKitCSharpString(field.name)}");`;
        });
    }

    function getGraphKitFieldAccessor(type) {
        const normalized = String(type || '').trim().toLowerCase();
        if (normalized === 'int' || normalized === 'int32') return 'GetInt32';
        if (normalized === 'long' || normalized === 'int64') return 'GetInt64';
        if (normalized === 'float' || normalized === 'single') return 'GetSingle';
        if (normalized === 'double') return 'GetDouble';
        if (normalized === 'bool' || normalized === 'boolean') return 'GetBoolean';
        return 'GetString';
    }

    function getGraphKitCSharpType(type) {
        const normalized = String(type || '').trim().toLowerCase();
        if (normalized === 'int' || normalized === 'int32') return 'int';
        if (normalized === 'long' || normalized === 'int64') return 'long';
        if (normalized === 'float' || normalized === 'single') return 'float';
        if (normalized === 'double') return 'double';
        if (normalized === 'bool' || normalized === 'boolean') return 'bool';
        return 'string';
    }

    function makeUniqueGraphKitHandlerClassName(handlerId, typeId, usedNames) {
        const source = String(handlerId || typeId || 'GraphNodeHandler');
        const base = toGraphKitHandlerClassName(source);
        let name = base.endsWith('Handler') ? base : `${base}Handler`;
        let index = 2;
        while (usedNames.has(name)) {
            name = `${base}Handler${index}`;
            index += 1;
        }
        usedNames.add(name);
        return name;
    }

    function toGraphKitHandlerClassName(value) {
        const text = String(value || '').trim();
        if (/^[A-Za-z_][A-Za-z0-9_]*$/.test(text)) return toGraphKitCSharpIdentifier(text, 'GraphNodeHandler', true);
        const tokens = text.split(/[^A-Za-z0-9]+/).filter(Boolean);
        const name = tokens.map(token => toGraphKitPascalToken(token)).join('');
        return toGraphKitCSharpIdentifier(name, 'GraphNodeHandler', true);
    }

    function toGraphKitPascalToken(token) {
        const text = String(token || '').replace(/[^A-Za-z0-9_]/g, '');
        if (!text) return '';
        return `${text.charAt(0).toUpperCase()}${text.slice(1)}`;
    }

    function toGraphKitCSharpIdentifier(value, fallback, pascal = false) {
        let text = String(value || '').replace(/[^A-Za-z0-9_]/g, '_').replace(/^_+/, '');
        if (!text) text = fallback;
        if (/^[0-9]/.test(text)) text = `_${text}`;
        if (pascal) text = `${text.charAt(0).toUpperCase()}${text.slice(1)}`;
        return text;
    }

    function escapeGraphKitCSharpString(value) {
        return String(value ?? '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
    }

    function escapeGraphKitCSharpComment(value) {
        return String(value ?? '').replace(/\r?\n/g, ' ').replace(/\*\//g, '* /');
    }

    function renderGraphKitScaffoldDock(scaffold, contract) {
        const handlerCount = Array.isArray(contract?.handlerIds) ? contract.handlerIds.length : 0;
        return `<details class="graphkit-scaffold-dock tablekit-json-panel">
        <summary>Handler Scaffold</summary>
        <div class="graphkit-xml-dock__meta">
            <span>${escapeHtml(`${handlerCount} handlers`)}</span>
            <span>${escapeHtml(contract?.handlerInterface || 'IGraphNodeHandler')}</span>
        </div>
        <div class="graphkit-xml-dock__actions">
            <button class="btn btn-secondary btn-sm" type="button" data-graphkit-action="copy-scaffold">复制 Scaffold</button>
        </div>
        <textarea class="cmd-input graphkit-xml-input graphkit-scaffold-output" data-graphkit-scaffold-output spellcheck="false" readonly>${escapeHtml(scaffold)}</textarea>
    </details>`;
    }

    async function copyGraphKitHandlerScaffold() {
        const scaffold = generateGraphKitHandlerScaffold(graphKitProject);
        try {
            await navigator.clipboard?.writeText?.(scaffold);
            setGraphKitNotice('success', 'Handler scaffold 已复制到剪贴板。');
        } catch (_) {
            setGraphKitNotice('warning', '剪贴板不可用，请直接复制 Scaffold 预览内容。');
        }
        renderGraphKitWorkbench();
    }

    const api = {
        copyGraphKitHandlerScaffold,
        generateGraphKitHandlerScaffold,
        renderGraphKitScaffoldDock,
    };

    if (typeof module !== 'undefined' && module.exports) {
        module.exports = api;
    }

    if (root) {
        Object.assign(root, api);
    }
})(typeof window !== 'undefined' ? window : globalThis);
